
.system-bar {
  padding: 8px 12px;
  background: linear-gradient(135deg, var(--c-surface) 0%, #e8eff7 100%);
  border-bottom: 1.5px solid var(--c-border);
}

.status-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.identity-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 0.82rem;
  font-weight: bold;
  transition: all 0.3s ease;

  &.active {
    background: linear-gradient(135deg, var(--c-primary), var(--c-accent));
    color: #fff;
    box-shadow: 0 1px 6px rgba(74, 127, 181, 0.3);
  }

  &.inactive {
    background: var(--c-border);
    color: var(--c-text-muted);
  }
}

.badge-icon {
  font-size: 0.9rem;
}

.meta-items {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 0.8rem;
  color: var(--c-text-muted);
}

.meta-item {
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.shipgirl-row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: 6px;
  padding-top: 5px;
  border-top: 1px dashed var(--c-border);
}

.shipgirl-label {
  color: var(--c-text-muted);
  font-size: 0.78rem;
  flex-shrink: 0;
}

.shipgirl-list {
  display: flex;
  gap: 4px;
  flex-wrap: wrap;
}

.shipgirl-tag {
  font-size: 0.72rem;
  padding: 1px 8px;
  border-radius: 10px;
  background: rgba(74, 127, 181, 0.1);
  color: var(--c-primary);
  border: 1px solid rgba(74, 127, 181, 0.2);
}
