
.card {
  width: 100%;
  max-width: 720px;
  background-color: var(--c-card);
  border: 2px solid var(--c-primary);
  border-radius: 10px;
  box-shadow:
    0 2px 12px rgba(74, 127, 181, 0.12),
    inset 0 1px 0 rgba(255, 255, 255, 0.6);
  display: flex;
  flex-direction: column;
  font-family: var(--font-main);
  color: var(--c-text);
  font-size: 13px;
  line-height: 1.4;
  margin: 0 auto;
  overflow: hidden;
}

.content-area {
  padding: 10px 12px;
}

.tab-pane {
  display: none;
  animation: fadeEffect 0.3s ease;
}

.tab-pane.active {
  display: block;
}

@keyframes fadeEffect {
  from {
    opacity: 0;
    transform: translateY(4px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.inactive-notice {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 20px 16px;
  gap: 4px;
}

.notice-icon {
  font-size: 1.6rem;
  color: var(--c-text-muted);
  opacity: 0.5;
}

.notice-text {
  font-size: 0.92rem;
  font-weight: bold;
  color: var(--c-text-muted);
}

.notice-sub {
  font-size: 0.76rem;
  color: var(--c-text-muted);
  opacity: 0.7;
}
