
.stage-section {
  padding: 8px 12px 10px;
  border-bottom: 1.5px solid var(--c-border);
}

.stage-header {
  display: flex;
  align-items: center;
  margin-bottom: 8px;
}

.stage-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 12px;
  border-radius: 4px;
  font-size: 0.88rem;
  font-weight: bold;
  color: #fff;

  &.stage-low {
    background: var(--c-indicator-low);
  }

  &.stage-mid {
    background: var(--c-indicator-mid);
  }

  &.stage-high {
    background: var(--c-indicator-high);
  }
}

.stage-star {
  font-size: 0.78rem;
}

.bars {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.stat-bar-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.stat-label {
  width: 42px;
  flex-shrink: 0;
  font-size: 0.76rem;
  color: var(--c-text-muted);
  text-align: right;
}

.stat-track {
  flex: 1;
  height: 8px;
  border-radius: 4px;
  background: var(--c-surface);
  border: 1px solid var(--c-border);
  position: relative;
  overflow: hidden;
}

.stat-fill {
  position: absolute;
  top: 0;
  left: 0;
  bottom: 0;
  border-radius: 3px;
  transition: width 0.4s ease, background 0.4s ease;

  &.stage-low {
    background: var(--c-indicator-low);
  }

  &.stage-mid {
    background: var(--c-indicator-mid);
  }

  &.stage-high {
    background: var(--c-indicator-high);
  }

  &.fill-danger {
    background: var(--c-danger);
  }
}

.dom-sub-center {
  position: absolute;
  top: -1px;
  bottom: -1px;
  left: 50%;
  width: 2px;
  background: var(--c-text-muted);
  opacity: 0.4;
  transform: translateX(-50%);
  z-index: 1;
}

.stat-value {
  width: 26px;
  flex-shrink: 0;
  font-size: 0.76rem;
  font-weight: bold;
  text-align: right;
  color: var(--c-text);
}
