
.clothing-panel {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.section-label {
  font-size: 0.82rem;
  font-weight: bold;
  color: var(--c-primary);
  padding-bottom: 4px;
  border-bottom: 1px solid var(--c-border);
}

.clothing-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 6px;
}

.clothing-item {
  padding: 5px 8px;
  border-radius: 6px;
  background: var(--c-surface);
  border: 1px solid var(--c-border);
  transition: all 0.2s;

  &.empty {
    opacity: 0.5;
    background: transparent;
    border-style: dashed;
  }
}

.clothing-slot {
  display: block;
  font-size: 0.68rem;
  color: var(--c-text-muted);
  margin-bottom: 1px;
}

.clothing-value {
  font-size: 0.78rem;
  line-height: 1.3;
  word-break: break-all;
}

@media (max-width: 500px) {
  .clothing-grid {
    grid-template-columns: 1fr;
  }
}
