
.thought-panel {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.section-label {
  font-size: 0.82rem;
  font-weight: bold;
  color: var(--c-primary);
  padding-bottom: 4px;
  border-bottom: 1px solid var(--c-border);
}

.thought-content {
  padding: 10px 12px;
  background: linear-gradient(135deg, var(--c-surface), #e8eff7);
  border-radius: 8px;
  border-left: 3px solid var(--c-accent);
  line-height: 1.5;
}

.thought-quote {
  color: var(--c-accent);
  font-size: 1.1rem;
  font-weight: bold;
  vertical-align: text-top;
  margin: 0 1px;
}

.thought-text {
  font-size: 0.82rem;
  color: var(--c-text);
}

.thought-empty {
  padding: 12px;
  text-align: center;
  color: var(--c-text-muted);
  font-size: 0.82rem;
  background: var(--c-surface);
  border-radius: 8px;
  border: 1px dashed var(--c-border);
}

.thought-empty-icon {
  display: block;
  font-size: 1.2rem;
  color: var(--c-indicator-low);
  margin-bottom: 4px;
}
